}: {
  isDark?: boolean;
  onTextClick?: () => void;
  latestRelease?: LatestRelease | null;
}) {
  return (
    <div className="relative w-full flex-col gap-8 pb-20 sm:pb-30">
      <MotionContainer
        className="relative z-2 flex h-full flex-col items-center justify-start gap-4 bg-transparent"
