367	function useSectionInView(
368	  ref: React.RefObject<HTMLElement | null>,
369	  threshold: number,
370	): boolean {
371	  const [inView, setInView] = useState(false);
372	
373	  useEffect(() => {
374	    const node = ref.current;
375	    if (!node) return;
376	    if (typeof IntersectionObserver === "undefined") {
377	      setInView(true);
378	      return;
379	    }
380	    const observer = new IntersectionObserver(
381	      ([entry]) => setInView(entry?.isIntersecting ?? false),
382	      { threshold },
383	    );
384	    observer.observe(node);
385	    return () => observer.disconnect();
386	  }, [ref, threshold]);
387	
388	  return inView;
389	}
