391	function FloatingCTA({
392	  isFloating,
393	  action,
394	  actionKey,
395	  iconSrc,
396	  comingSoon,
397	  onPrev,
398	  onNext,
399	}: {
400	  isFloating: boolean;
401	  action: ActionLink;
402	  actionKey: string;
403	  iconSrc: string | undefined;
404	  comingSoon?: boolean;
405	  onPrev: () => void;
406	  onNext: () => void;
407	}) {
408	  // Reserve the static-flow slot so the layout never jumps when the button
409	  // pops out of the flow into a fixed position. The CTA is rendered twice:
410	  //   - In flow, invisible while floating (reserves space)
411	  //   - Fixed at the bottom while floating, fades in via opacity only
412	  return (
413	    <div className="relative flex w-full justify-center pt-2">
414	      <div
415	        aria-hidden={isFloating}
416	        className={isFloating ? "pointer-events-none opacity-0" : "opacity-100"}
417	      >
418	        <CTAGroup
419	          actionKey={actionKey}
420	          action={action}
421	          iconSrc={iconSrc}
