430	          <m.div
431	            key="floating"
432	            initial={{ opacity: 0 }}
433	            animate={{ opacity: 1 }}
434	            exit={{ opacity: 0 }}
435	            transition={{ duration: 0.18, ease: "easeOut" }}
436	            className="pointer-events-none fixed inset-x-0 bottom-6 z-[1001] flex justify-center px-4"
437	          >
