441	                action={action}
442	                iconSrc={iconSrc}
443	                comingSoon={comingSoon}
444	                onPrev={onPrev}
445	                onNext={onNext}
446	              />
447	            </div>
448	          </m.div>
449	        )}
450	      </AnimatePresence>
451	    </div>
452	  );
453	}
