528	function useFloatingCta(
529	  phoneRef: React.RefObject<HTMLDivElement | null>,
530	): boolean {
531	  const [floating, setFloating] = useState(false);
532	
533	  useEffect(() => {
534	    const phone = phoneRef.current;
535	    if (!phone) return;
536	
537	    const update = (): void => {
538	      const phoneRect = phone.getBoundingClientRect();
539	      const vh = window.innerHeight;
540	      // Threshold is tuned so the floating button and its static-flow slot
541	      // line up vertically at the moment of switch — the visual position
542	      // doesn't jump.
543	      const phoneEnoughVisible = phoneRect.top < vh - 200;
544	      // The floating button sits at vh - 56 (bottom-6 + button height). The
545	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
546	      // button). The switch happens when the two y positions match.
547	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
548	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
549	    };
550	
551	    update();
552	    window.addEventListener("scroll", update, { passive: true });
553	    window.addEventListener("resize", update);
554	    return () => {
555	      window.removeEventListener("scroll", update);
556	      window.removeEventListener("resize", update);
557	    };
558	  }, [phoneRef]);
559	
560	  return floating;
561	}
