563	const TYPING_DELAY_MS = 450;
564	const TYPING_DURATION_MS = 850;
565	
566	function useStaggeredMessages(
567	  platform: Platform,
568	  enabled: boolean,
569	): ChatMessageItem[] {
570	  const allMessages = platform.demo.messages;
571	  const [visibleCount, setVisibleCount] = useState(1);
572	  const [showTyping, setShowTyping] = useState(false);
573	
574	  useEffect(() => {
575	    setVisibleCount(1);
576	    setShowTyping(false);
577	    if (!enabled) return;
578	    if (allMessages.length <= 1) return;
579	
580	    const timers: ReturnType<typeof setTimeout>[] = [];
581	    let elapsed = 0;
582	    for (let i = 1; i < allMessages.length; i++) {
583	      elapsed += TYPING_DELAY_MS;
584	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
585	      elapsed += TYPING_DURATION_MS;
586	      timers.push(
587	        setTimeout(() => {
588	          setShowTyping(false);
589	          setVisibleCount((c) => c + 1);
590	        }, elapsed),
591	      );
592	    }
593	
594	    return () => {
595	      for (const t of timers) clearTimeout(t);
596	    };
597	  }, [allMessages, enabled]);
598	
599	  return useMemo(() => {
600	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
601	      ...m,
602	      id: m.id ?? `msg-${i}`,
603	    }));
604	    if (!showTyping || visibleCount >= allMessages.length) return real;
605	    const next = allMessages[visibleCount];
606	    return [
607	      ...real,
608	      {
609	        id: `typing-${visibleCount}`,
610	        from: next.from,
611	        author: next.author,
612	        avatar: next.avatar,
613	        authorColor: next.authorColor,
614	        typing: true,
615	      },
616	    ];
617	  }, [allMessages, visibleCount, showTyping]);
618	}
