659	                  className="flex h-5 w-5 shrink-0 items-center justify-center"
660	                  aria-hidden
661	                >
662	                  {p.icon}
663	                </span>
664	              )
665	            }
666	          >
667	            {p.name}
668	          </Chip>
669	        );
670	      })}
671	    </div>
672	  );
673	}
