687	        style={{
688	          backgroundImage:
689	            "radial-gradient(closest-side, rgba(0,187,255,0.7), rgba(0,187,255,0.25) 35%, rgba(0,187,255,0.06) 65%, transparent 80%)",
690	          filter: "blur(18px)",
